+/// Try to simplify a switch on a ucmp/scmp intrinsic into a branch.
+/// The ucmp/scmp intrinsic returns -1 if a < b, 0 if a == b, 1 if a > b.
+/// For example:
+///   %res = call i8 @llvm.ucmp.i8.i32(i32 %a, i32 %b)
+///   switch i8 %res, label %bb1 [i8 -1, label %bb2, i8 0, label %bb2]
+/// can be simplified to:
+///   %cmp = icmp ugt i32 %a, %b
+///   br i1 %cmp, label %bb1, label %bb2
+static bool simplifySwitchOnCmpIntrinsic(SwitchInst *SI, IRBuilder<> &Builder) {
+  Value *Cond = SI->getCondition();
+  auto *II = dyn_cast<IntrinsicInst>(Cond);
+  if (!II)
+    return false;
+
+  Intrinsic::ID ID = II->getIntrinsicID();
+  if (ID != Intrinsic::ucmp && ID != Intrinsic::scmp)
+    return false;
+
+  // Get the comparison arguments
+  Value *LHS = II->getOperand(0);
+  Value *RHS = II->getOperand(1);
+  bool IsSigned = (ID == Intrinsic::scmp);
+
+  // The ucmp/scmp intrinsic returns -1, 0, or 1
+  // We need to analyze the switch cases to determine the predicate
+
+  // Track which value goes to which destination
+  BasicBlock *DefaultDest = SI->getDefaultDest();
+  BasicBlock *DestFor1 = DefaultDest;
+  BasicBlock *DestFor0 = DefaultDest;
+  BasicBlock *DestForNeg1 = DefaultDest;
+
+  for (auto Case : SI->cases()) {
+    ConstantInt *CaseVal = Case.getCaseValue();
+    const APInt &Val = CaseVal->getValue();
+    BasicBlock *Succ = Case.getCaseSuccessor();
+    
+    // Check if the value is 1, 0, or -1
+    if (Val.isOne()) {
+      DestFor1 = Succ;
+    } else if (Val.isZero()) {
+      DestFor0 = Succ;
+    } else if (Val.isAllOnes()) {
+      DestForNeg1 = Succ;
+    } else {
+      // Unexpected value - can't optimize
+      return false;
+    }
+  }
+
+  // Now we have the destinations for each possible value
+  // Determine the predicate based on the pattern
+
+  ICmpInst::Predicate Pred = ICmpInst::ICMP_NE; // Default to something invalid
+  BasicBlock *TrueDest = nullptr;
+  BasicBlock *FalseDest = nullptr;
+
+  // Pattern 1/3: DestFor0 == DestForNeg1 && DestFor1 != DestFor0
+  // Pattern 1: 1 -> A, 0 -> B, -1 -> B  =>  A is for > (gt), br GT to A
+  // Pattern 3: 1 -> B, 0 -> A, -1 -> A  =>  A is for <= (le), br LE to A
+  // These are complementary - we use GT if TrueDest is DestFor1, LE otherwise
+  if (DestFor1 != DestFor0 && DestFor0 == DestForNeg1) {
+    // Check if the desired true destination is DestFor1 (GT) or DestFor0 (LE)
+    // We want to create the most natural form: GT if DestFor1 is "separate"
+    Pred = IsSigned ? ICmpInst::ICMP_SGT : ICmpInst::ICMP_UGT;
+    TrueDest = DestFor1;
+    FalseDest = DestFor0;
+  }
+  // Pattern 2/4: DestFor1 == DestFor0 && DestFor0 != DestForNeg1
+  // Pattern 2: 1 -> A, 0 -> A, -1 -> B  =>  A is for >= (ge), br GE to A
+  // Pattern 4: 1 -> B, 0 -> B, -1 -> A  =>  A is for < (lt), br LT to A
+  else if (DestFor1 == DestFor0 && DestFor0 != DestForNeg1) {
+    Pred = IsSigned ? ICmpInst::ICMP_SGE : ICmpInst::ICMP_UGE;
+    TrueDest = DestFor1;
+    FalseDest = DestForNeg1;
+  }
+  // Pattern 5/6: DestFor1 == DestForNeg1 && DestFor0 != DestFor1
+  // Pattern 5: 1 -> A, 0 -> B, -1 -> A  =>  A is for != (ne), br NE to A
+  // Pattern 6: 1 -> B, 0 -> A, -1 -> B  =>  A is for == (eq), br EQ to A
+  else if (DestFor1 == DestForNeg1 && DestFor0 != DestFor1) {
+    Pred = ICmpInst::ICMP_NE;
+    TrueDest = DestFor1;
+    FalseDest = DestFor0;
+  }
+  else {
+    // All three go to same dest - should have been folded already
+    // Or some other pattern we don't handle
+    return false;
+  }
+  // Create the comparison and branch
+  Builder.SetInsertPoint(SI);
+  Value *Cmp = Builder.CreateICmp(Pred, LHS, RHS, "cmp");
+  BranchInst::Create(TrueDest, FalseDest, Cmp, SI);
+
+  // Remove the switch
+  SI->eraseFromParent();
+
+  // Clean up the ucmp/scmp intrinsic if it's now dead
+  if (II->use_empty())
+    II->eraseFromParent();
+
+  return true;
+}
+
 /// Turn a switch into an integer range comparison and branch.
+
 /// Switches with more than 2 destinations are ignored.
 /// Switches with 1 destination are also ignored.
 bool SimplifyCFGOpt::turnSwitchRangeIntoICmp(SwitchInst *SI,
@@ -7153,6 +7258,11 @@ bool SimplifyCFGOpt::simplifySwitch(SwitchInst *SI, IRBuilder<> &Builder) {
         return requestResimplify();
   }

+
+  // Try to simplify a switch on ucmp/scmp intrinsic into a branch.
+  if (simplifySwitchOnCmpIntrinsic(SI, Builder))
+    return requestResimplify();
+
   // Try to transform the switch into an icmp and a branch.
   // The conversion from switch to comparison may lose information on
   // impossible switch values, so disable it early in the pipeline.
